$:/plugins/kookma/utility/styles/centere.text:
\rules only filteredtranscludeinline transcludeinline macrodef macrocallinline html
<$list filter='[[$:/state/sidebar]get[text]match[no]]'variable=null>
:not([data-tiddler-title^="Draft of '"]).tc-tiddler-frame  {
min-width: 600px;
max-width: 50vw;
margin-left: auto;
margin-right: auto;
}

$:/plugins/kookma/utility/styles/tw-vers.text:
/* TW-version added to site title */
.tc-site-title:before {
  content:"TW <<version>>";
  position:absolute;
  margin-top:-1.9em;
  color:silver;
  font-size:13px;
}

$:/plugins/kookma/utility/styles/wikitex.text:
.doc-example {
	margin: 1em 0;
	padding: 0.8em 0;
}
.doc-example:hover {
	background-color: <<colour code-background>>;
}
.doc-example ul {
	margin-bottom: 0;
	padding-bottom: 0;
	margin-top: 0.2em;
}

.doc-example input[type=search] { 
  width: 95%;
}
.doc-example pre:first-child {
	margin-top: 0;
}
